    /* Use strncpy to prevent buffer overflow, ensure null termination */
    strncpy(key_store[i].key, api_key, sizeof(key_store[i].key) - 1);
    key_store[i].key[sizeof(key_store[i].key) - 1] = '\0';

    /* Safely copy user_info with bounds checking and null termination */
    strncpy(key_store[i].user, user_info, sizeof(key_store[i].user) - 1);
    key_store[i].user[sizeof(key_store[i].user) - 1] = '\0';

    /* Initialize permissions to default value */
    key_store[i].permissions = 0;

    /* Compute hash value of the API key for lookup and verification */
    hash_value = hash_string(api_key);

    /* Ensure hash is non-zero for success indication */
    if (hash_value == 0) {
        hash_value = 1;
    }

    return hash_value;
}
